noncompliant:
// Noncompliant: First declaration has static, but redeclaration doesn't
static int helper_function(int x);

// Later in the same file or another file
int helper_function(int x) {  // Missing static keyword
    return x * 2;
}

compliant:
// Compliant: Both declaration and definition use static
static int helper_function(int x);

// Definition also includes static
static int helper_function(int x) {
    return x * 2;
}
